0.000' AS TIMESTAMP) AS VARCHAR), CAST(dateSubtractQuantity(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), '{"value": 3.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(dateSubtractQuantity(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), '{"value": 3.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(dateSubtractQuantity(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), '{"value": 3.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR))
),
"Encounter With Antibiotic Ordered Within Three Days" AS (
SELECT * FROM "Qualifying Encounters" AS EDOrAmbulatoryVisit WHERE EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "MedicationRequest: Antibiotic Medications for Pharyngitis" WHERE fhirpath_text(resource, 'status') IN ('active', 'completed') AND fhirpath_text(resource, 'intent') IN ('order', 'original-order', 'reflex-order', 'filler-order', 'instance-order')) AS AntibioticOrdered WHERE LEFT(REPLACE(CAST(REPLACE(CAST(CAST(CAST(LEFT(REPLACE(CAST(fhirpath_text(AntibioticOrdered.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP) - INTERVAL '3 day' AS VARCHAR), ' ', 'T') AS VARCHAR), ' ', 'T'), 10) <= CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(EDOrAmbulatoryVisit.resource, 'period') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(EDOrAmbulatoryVisit.resource, 'period')), '{') THEN fhirpath_text(EDOrAmbulatoryVisit.resource, 'period') ELSE intervalFromBounds(fhirpath_text(EDOrAmbulatoryVisit.resource, 'period'), fhirpath_text(EDOrAmbulatoryVisit.resource, 'period'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(EDOrAmbulatoryVisit.resource, 'period') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(EDOrAmbulatoryVisit.resource, 'period')), '{') THEN fhirpath_text(EDOrAmbulatoryVisit.resource, 'period') ELSE intervalFromBounds(fhirpath_text(EDOrAmbulatoryVisit.resource, 'period'), fhirpath_text(EDOrAmbulatoryVisit.resource, 'period'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= LEFT(REPLACE(CAST(CAST(LEFT(REPLACE(CAST(fhirpath_text(AntibioticOrdered.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS VARCHAR), ' ', 'T'), 10) AND AntibioticOrdered.patient_id = EDOrAmbulatoryVisit.patient_id)
