(CASE WHEN fhirpath_text(competcondition.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(competcondition.resource, 'onsetDateTime'), fhirpath_text(competcondition.resource, 'onsetPeriod.start'), fhirpath_text(competcondition.resource, 'recordedDate')), fhirpath_text(competcondition.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(competcondition.resource, 'onsetDateTime'), fhirpath_text(competcondition.resource, 'onsetPeriod.start'), fhirpath_text(competcondition.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(competcondition.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(competcondition.resource, 'onsetDateTime'), fhirpath_text(competcondition.resource, 'onsetPeriod.start'), fhirpath_text(competcondition.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(competcondition.resource, 'onsetDateTime'), fhirpath_text(competcondition.resource, 'onsetPeriod.start'), fhirpath_text(competcondition.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= LEFT(REPLACE(CAST(REPLACE(CAST(CAST(CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(eDate.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP) + INTERVAL '3 day' AS VARCHAR), ' ', 'T') AS VARCHAR), ' ', 'T'), 10) AND competcondition.patient_id = eDate.patient_id))
),
"Numerator" AS (
SELECT GroupAStreptococcusTest.patient_id, CAST(EncounterWithPharyngitis.resource AS VARCHAR) AS resource FROM "Group A Streptococcus Lab Test With Result" AS GroupAStreptococcusTest CROSS JOIN (SELECT * FROM "Encounter With Pharyngitis or Tonsillitis With Antibiotic") AS EncounterWithPharyngitis WHERE CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(GroupAStreptococcusTest.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(GroupAStreptococcusTest.resource, 'effective')), '{') THEN fhirpath_text(GroupAStreptococcusTest.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(GroupAStreptococcusTest.resource, 'effective'), fhirpath_text(GroupAStreptococcusTest.resource, 'effective'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) BETWEEN CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalEnd(fhirpath_text(EncounterWithPharyngitis.resource, 'period')) AS VARCHAR), '{"value": 3.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(dateAddQuantity(CAST(intervalEnd(fhirpath_text(EncounterWithPharyngitis.resource, 'period')) AS VARCHAR), '{"value": 3.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalEnd(fhirpath_text(EncounterWithPharyngitis.resource, 'period')) AS VARCHAR), '{"value": 3.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(dateAddQuantity(CAST(intervalEnd(fhirpath_text(EncounterWithPharyngitis.resource, 'period')) AS VARCHAR), '{"value": 3.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalEnd(fhirpath_text(EncounterWithPharyngitis.resource, 'period')) AS VARCHAR), '{"value": 3.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(dateAddQuantity(CAST(intervalEnd(fhirpath_text(EncounterWithPharyngitis.resource, 'period')) AS VARCHAR), '{"value": 3.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)) AND EncounterWithPharyngitis.patient_id = GroupAStreptococcusTest.patient_id
